// Active waveform selector (all stored in Flash)
static const uint16_t *waveforms[6] = {
	sine_lut, square_lut, triangle_lut, sawtooth_lut,
	step_lut, trapezoid_lut
};

static const uint16_t waveform_lengths[] = {
	sizeof(sine_lut)/sizeof(uint16_t),
	sizeof(square_lut)/sizeof(uint16_t),
	sizeof(triangle_lut)/sizeof(uint16_t),
	sizeof(sawtooth_lut)/sizeof(uint16_t),
	sizeof(step_lut)/sizeof(uint16_t),
	sizeof(trapezoid_lut)/sizeof(uint16_t)
};

static waveform_t active_wave = SINE;
static volatile uint16_t wave_idx = 0;

void waveform_init(void) {
	/****** Enable APB Clocks ******/
	MCLK_REGS->MCLK_APBCMASK |= MCLK_APBCMASK_DAC_Msk;

	/****** GPIO Configuration ******/
	// PA02 for DAC - mux to function B
	PORT_REGS->GROUP[0].PORT_PINCFG[2] = PORT_PINCFG_PMUXEN_Msk;
	PORT_REGS->GROUP[0].PORT_PMUX[1] =
		(PORT_REGS->GROUP[0].PORT_PMUX[1] & ~PORT_PMUX_PMUXE_Msk) |
		PORT_PMUX_PMUXE_B_Val;

	/****** Clock Routing ******/
	GCLK_SetPeripheralChannelGenSrc(DAC_GCLK_ID, 0);
	GCLK_EnablePeripheralChannel(DAC_GCLK_ID);

	/****** DAC Initialization (using PLIB) ******/
	DAC_SetReference(DAC_REFSEL_AVDD);
	DAC_SetOutputMode(DAC_OUTPUT_MODE_EXTERNAL);
	DAC_Enable();

	printf("Waveform generator ready. Commands: 1=sine, 2=square, 3=triangle, 4=sawtooth, 5=step, 6=trapezoid\r\n");
}

void waveform_update(void) {
	if (active_wave >= 6) active_wave = SINE;
	uint16_t len = waveform_lengths[active_wave];
	DAC_WriteData(waveforms[active_wave][wave_idx]);
	wave_idx++;
	if (wave_idx >= len) wave_idx = 0;
}

void waveform_set_type(waveform_t type) {
	active_wave = type;
	wave_idx = 0;
}

waveform_t waveform_get_type(void) {
	return active_wave;
}
